const n_linear = [];
for (let i = 1; i <= 50; i += 1) { n_linear.push(i); }

const n_smooth = [];
for (let i = 1; i <= 50; i += 0.5) { n_smooth.push(i); }

const data = [
  {
    x: n_linear,
    y: n_linear.map(() => 1),
    name: 'O(1) - Constant',
    type: 'scatter',
    mode: 'lines',
    line: { color: '#94a3b8', width: 3 }
  },
  {
    x: n_smooth,
    y: n_smooth.map(n => Math.log2(n)),
    name: 'O(log n) - Logarithmic',
    type: 'scatter',
    mode: 'lines',
    line: { color: '#10b981', width: 3 }
  },
  {
    x: n_linear,
    y: n_linear,
    name: 'O(n) - Linear',
    type: 'scatter',
    mode: 'lines',
    line: { color: '#3b82f6', width: 3 }
  },
  {
    x: n_smooth,
    y: n_smooth.map(n => n * Math.log2(n)),
    name: 'O(n log n) - Log-linear',
    type: 'scatter',
    mode: 'lines',
    line: { color: '#f59e0b', width: 3 }
  },
  {
    x: n_smooth,
    y: n_smooth.map(n => Math.pow(n, 2)),
    name: 'O(n²) - Quadratic',
    type: 'scatter',
    mode: 'lines',
    line: { color: '#f97316', width: 3 }
  },
  {
    x: n_smooth,
    y: n_smooth.map(n => Math.pow(n, 3)),
    name: 'O(n³) - Cubic',
    type: 'scatter',
    mode: 'lines',
    line: { color: '#ef4444', width: 3 }
  },
  {
    x: n_smooth.filter(n => n <= 12),
    y: n_smooth.filter(n => n <= 12).map(n => Math.pow(2, n)),
    name: 'O(2ⁿ) - Exponential',
    type: 'scatter',
    mode: 'lines',
    line: { color: '#ec4899', width: 3, dash: 'dot' }
  }
];
return data;
